const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const safeFilename = items[i].json.name.normalize('NFC').replace(/\s+/g, '_');
  items[i].json.nombre_archivo_limpio = safeFilename;
}

return items;

const fs = require('fs');
const items = $input.all();
const base64Script = '';

for (let i = 0; i < items.length; i++) {
  const safeFilename = Normalizar Nombre.item.json.nombre_archivo_limpio;

  if (safeFilename === 'Ingesta_PDF_WEB.py') {
    const scriptBuffer = Buffer.from(base64Script, 'base64');
    fs.writeFileSync('/opt/RAG/implementacion_SARA/Ingesta_PDF_WEB.py', scriptBuffer);
    items[i].json.reparado = true;
  }
}

return items;

